4	const gridToLiveCells = (grid: Grid): Set<string> => {
5	  const live = new Set<string>();
6	  for (let r = 0; r < grid.length; r++) {
7	    for (let c = 0; c < (grid[r]?.length ?? 0); c++) {
8	      if (grid[r][c] === 1) live.add(`${r},${c}`);
9	    }
10	  }
11	  return live;
12	};
