14	const getNeighborCoords = (r: number, c: number): Coord[] => {
15	  const neighbors: Coord[] = [];
16	  for (let dr = -1; dr <= 1; dr++) {
17	    for (let dc = -1; dc <= 1; dc++) {
18	      if (dr === 0 && dc === 0) continue;
19	      neighbors.push([r + dr, c + dc]);
20	    }
21	  }
22	  return neighbors;
23	};
24	
25	const countLiveNeighbors = (live: Set<string>, r: number, c: number): number => {
26	  return getNeighborCoords(r, c).filter(([nr, nc]) => live.has(`${nr},${nc}`)).length;
27	};
28	
29	const willCellLive = (alive: boolean, neighbors: number): boolean =>
30	  (alive && (neighbors === 2 || neighbors === 3)) || (!alive && neighbors === 3);
31	
32	const liveCellsToGrid = (nextLive: Set<string>): Grid => {
33	  if (nextLive.size === 0) return [];
34	  const coords = [...nextLive].map(s => s.split(",").map(Number) as [number, number]);
35	  const minR = Math.min(...coords.map(([r]) => r));
36	  const maxR = Math.max(...coords.map(([r]) => r));
37	  const minC = Math.min(...coords.map(([, c]) => c));
38	  const maxC = Math.max(...coords.map(([, c]) => c));
39	  const grid: Grid = [];
40	  for (let r = minR; r <= maxR; r++) {
41	    const row: number[] = [];
42	    for (let c = minC; c <= maxC; c++) {
43	      row.push(nextLive.has(`${r},${c}`) ? 1 : 0);
44	    }
45	    grid.push(row);
46	  }
47	  return grid;
48	};
49	
50	export function nextGeneration(grid: Grid): Grid {
51	  if (grid.length === 0) return [];
52	  const live = gridToLiveCells(grid);
53	  if (live.size === 0) return [];
54	
55	  const candidates = new Set<string>();
56	  for (const key of live) {
57	    candidates.add(key);
58	    const [r, c] = key.split(",").map(Number);
59	    for (const [nr, nc] of getNeighborCoords(r, c)) {
60	      candidates.add(`${nr},${nc}`);
61	    }
62	  }
63	
64	  const nextLive = new Set<string>();
65	  for (const key of candidates) {
66	    const [r, c] = key.split(",").map(Number);
67	    const alive = live.has(key);
68	    const neighbors = countLiveNeighbors(live, r, c);
69	    if (willCellLive(alive, neighbors)) {
70	      nextLive.add(key);
71	    }
72	  }
73	
74	  return liveCellsToGrid(nextLive);
75	}
