4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[1]])).toEqual([]);
10	  });
11	  it("should return empty grid when two cells die from underpopulation", () => {
12	    expect(nextGeneration([[1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Horizontal blinker [[1,1,1]]: middle cell survives with 2 neighbors,
16	    // edge cells die, but dead cells above/below middle are born (3 neighbors each)
17	    // Result is vertical blinker [[1],[1],[1]]
18	    expect(nextGeneration([[1, 1, 1]])).toEqual([[1], [1], [1]]);
19	  });
20	  it("should keep a live cell alive when it has 3 live neighbors (survival)", () => {
21	    // In a 2x2 grid of all live cells, each cell has exactly 3 live neighbors, so all survive
22	    expect(nextGeneration([[1, 1], [1, 1]])).toEqual([[1, 1], [1, 1]]);
23	  });
24	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
25	    // [[1,1,1],[1,1,1]]: center cells (0,1) and (1,1) each have 5 neighbors -> die
26	    // Dead cells above/below the center column are born (3 neighbors each)
27	    expect(nextGeneration([[1, 1, 1], [1, 1, 1]])).toEqual([[0, 1, 0], [1, 0, 1], [1, 0, 1], [0, 1, 0]]);
28	  });
29	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
30	    // Dead cell at (1,1) has 3 live neighbors: (0,0), (0,1), (1,0) -> comes alive
31	    // All three live cells each have exactly 2 live neighbors -> survive
32	    expect(nextGeneration([[1, 1], [1, 0]])).toEqual([[1, 1], [1, 1]]);
33	  });
34	  it("should compute next generation for the block (still life)", () => {
35	    // The block is a 2x2 grid of live cells - a still life pattern that never changes
36	    expect(nextGeneration([[1, 1], [1, 1]])).toEqual([[1, 1], [1, 1]]);
37	  });
38	  it("should compute next generation for the blinker (oscillator, first step)", () => {
39	    // Blinker: horizontal [[1,1,1]] -> vertical [[1],[1],[1]]
40	    expect(nextGeneration([[1, 1, 1]])).toEqual([[1], [1], [1]]);
41	  });
